17	// WorkerProgress is the resolver for the workerProgress subscription.
18	// It wraps ProgressSubscriber.SubscribeProgress to stream FEAT-006 progress
19	// events for the given worker as GraphQL WorkerEvent values.
20	func (r *subscriptionResolver) WorkerProgress(ctx context.Context, workerID string) (<-chan *WorkerEvent, error) {
21		if r.Workers == nil {
22			return nil, fmt.Errorf("subscription not available: workers not configured")
23		}
24	
25		src, unsub := r.Workers.SubscribeProgress(workerID)
26		out := make(chan *WorkerEvent, 16)
27	
28		go func() {
29			defer unsub()
30			defer close(out)
31			for {
32				select {
33				case <-ctx.Done():
34					return
35				case evt, ok := <-src:
36					if !ok {
37						return
38					}
39					ts := evt.TS.Format(time.RFC3339)
40					we := &WorkerEvent{
41						EventID:   evt.EventID,
42						WorkerID:  evt.WorkerID,
43						Phase:     evt.Phase,
44						Timestamp: ts,
45					}
46					if evt.Message != "" {
47						we.LogLine = &evt.Message
48					}
49					if evt.BeadID != "" {
50						beadID := evt.BeadID
51						we.BeadID = &beadID
52					}
53					select {
54					case out <- we:
55					case <-ctx.Done():
56						return
57					}
58				}
59			}
60		}()
