132	// ResolvedLadder returns the escalation ladder for the named profile. If
133	// ProfileLadders contains an entry for profile, that wins. Otherwise falls
134	// back to the deprecated ProfilePriority for the default profile only. If
135	// neither is set, returns the shipped FEAT-006 profile ladder.
136	func (r *RoutingConfig) ResolvedLadder(profile string) []string {
137		if profile == "" {
138			profile = "default"
139		}
140		if r == nil {
141			if ladder, ok := defaultProfileLadders[profile]; ok {
142				return append([]string(nil), ladder...)
143			}
144			return append([]string(nil), defaultProfileLadders["default"]...)
145		}
146		if r.ProfileLadders != nil {
147			if ladder, ok := r.ProfileLadders[profile]; ok && len(ladder) > 0 {
148				return append([]string(nil), ladder...)
149			}
150		}
151		if profile == "default" && len(r.ProfilePriority) > 0 {
152			return append([]string(nil), r.ProfilePriority...)
153		}
154		if ladder, ok := defaultProfileLadders[profile]; ok {
155			return append([]string(nil), ladder...)
156		}
157		return append([]string(nil), defaultProfileLadders["default"]...)
158	}
