package server

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"
)

// TestWorkerDispatchAdapterEnforcesMaxCount covers the workers.max_count
// safety rail (ddx-b6cf025c). When max_count is set and the current count of
// running execute-loop workers already meets the cap, the adapter must
// refuse the dispatch with a clear error.
func TestWorkerDispatchAdapterEnforcesMaxCount(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	// Seed config with max_count: 1.
	cfgPath := filepath.Join(root, ".ddx", "config.yaml")
	cfg := "version: \"1.0\"\nbead:\n  id_prefix: \"it\"\nworkers:\n  max_count: 1\n"
	if err := os.WriteFile(cfgPath, []byte(cfg), 0o644); err != nil {
		t.Fatal(err)
	}

	m := NewWorkerManager(root)
	defer m.StopWatchdog()

	// Seed one running drain worker on disk for this projectRoot.
	seedWorkerRecord(t, m, WorkerRecord{
		ID:          "worker-pre-existing",
		Kind:        "execute-loop",
		State:       "running",
		Status:      "running",
		ProjectRoot: root,
		StartedAt:   time.Now().UTC(),
	})

	adapter := &workerDispatchAdapter{manager: m}
	_, err := adapter.DispatchWorker(context.Background(), "execute-loop", root, nil)
	if err == nil {
		t.Fatal("expected error when max_count reached, got nil")
	}
	if !strings.Contains(err.Error(), "max_count") {
		t.Fatalf("error should mention max_count, got: %v", err)
	}
}

// TestWorkerDispatchAdapterDefaultSpecAppliesConfigDefaults covers the
// workers.default_spec path (ddx-b6cf025c). When args is nil, the adapter
// must read config defaults and pass them through to StartExecuteLoop.
// Verified by intercepting the spec file written to disk.
func TestWorkerDispatchAdapterDefaultSpecAppliesConfigDefaults(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	cfg := `version: "1.0"
bead:
  id_prefix: "it"
workers:
  default_spec:
    profile: cheap
    effort: low
`
	if err := os.WriteFile(filepath.Join(root, ".ddx", "config.yaml"), []byte(cfg), 0o644); err != nil {
		t.Fatal(err)
	}

	m := NewWorkerManager(root)
	defer m.StopWatchdog()
	// Bypass harness validation and the real agent runner by installing a
	// no-op factory; the seeded "virtual" harness is recognised by
	// ValidateForExecuteLoopViaService for empty harness fallback.
	m.BeadWorkerFactory = nopBeadWorkerFactory

	adapter := &workerDispatchAdapter{manager: m}
	result, err := adapter.DispatchWorker(context.Background(), "execute-loop", root, nil)
	if err != nil {
		t.Fatalf("dispatch: %v", err)
	}
	defer func() { _ = m.Stop(result.ID) }()

	specPath := filepath.Join(m.rootDir, result.ID, "spec.json")
	data := mustReadFileEventually(t, specPath, 3*time.Second)
	var spec ExecuteLoopWorkerSpec
	if err := json.Unmarshal(data, &spec); err != nil {
		t.Fatalf("parse spec.json: %v", err)
	}
	if spec.Profile != "cheap" {
		t.Errorf("profile: want cheap, got %q", spec.Profile)
	}
	if spec.Effort != "low" {
		t.Errorf("effort: want low, got %q", spec.Effort)
	}
}

func mustReadFileEventually(t *testing.T, path string, timeout time.Duration) []byte {
	t.Helper()
	deadline := time.Now().Add(timeout)
	for {
		data, err := os.ReadFile(path)
		if err == nil && len(data) > 0 {
			return data
		}
		if time.Now().After(deadline) {
			t.Fatalf("file %s not ready: %v", path, err)
		}
		time.Sleep(20 * time.Millisecond)
	}
}

